62	// withExecutionWallClock attaches an absolute wall-clock deadline to ctx.
63	// Unlike withExecutionTimeout — which is an idle (inactivity) timer that
64	// resets on every stream byte or event — this bound fires regardless of
65	// activity so a chatty provider cannot pin the worker indefinitely.
66	func withExecutionWallClock(ctx context.Context, wallClock time.Duration) context.Context {
67		if wallClock <= 0 {
68			return ctx
69		}
70		return context.WithValue(ctx, executionWallClockKey{}, wallClock)
71	}
