101	// authCancelPatterns are regexps matched against lowercased stderr lines that indicate
102	// the subprocess will never succeed and should be cancelled immediately.
103	// Numeric HTTP codes use word-boundary anchors to avoid false positives (e.g. "port 4290").
104	// Overly broad patterns like "credential" and "please run" are intentionally excluded.
105	var authCancelPatterns = []*regexp.Regexp{
106		regexp.MustCompile(`\b429\b`),
107		regexp.MustCompile(`\b401\b`),
108		regexp.MustCompile(`\b403\b`),
109		regexp.MustCompile(`rate limit`),
110		regexp.MustCompile(`ratelimit`),
111		regexp.MustCompile(`quota exceeded`),
112		regexp.MustCompile(`quota_exceeded`),
113		regexp.MustCompile(`not logged in`),
114		regexp.MustCompile(`not signed in`),
115		regexp.MustCompile(`no credentials`),
116		regexp.MustCompile(`authentication required`),
117		regexp.MustCompile(`authentication failed`),
118		regexp.MustCompile(`unauthorized`),
119		regexp.MustCompile(`unauthenticated`),
120		regexp.MustCompile(`invalid api key`),
121		regexp.MustCompile(`invalid_api_key`),
122		regexp.MustCompile(`api key not found`),
123		regexp.MustCompile(`insufficient credits`),
124		regexp.MustCompile(`insufficient_credits`),
125		regexp.MustCompile(`login required`),
126		regexp.MustCompile(`api key expired`),
127		regexp.MustCompile(`token expired`),
128	}
129	
130	// matchesCancelPattern returns the matched pattern string if line matches a known
131	// auth/rate-limit pattern that warrants early cancellation, empty string otherwise.
132	func matchesCancelPattern(line string) string {
133		lower := strings.ToLower(line)
134		for _, p := range authCancelPatterns {
135			if p.MatchString(lower) {
136				return p.String()
137			}
138		}
139		return ""
140	}
