337	func envWithOverrides(base []string, overrides map[string]string) []string {
338		if len(base) == 0 && len(overrides) == 0 {
339			return nil
340		}
341		if len(overrides) == 0 {
342			return append([]string{}, base...)
343		}
344	
345		skip := make(map[string]bool, len(overrides))
346		keys := make([]string, 0, len(overrides))
347		for key := range overrides {
348			skip[key] = true
349			keys = append(keys, key)
350		}
351		sort.Strings(keys)
352	
353		env := make([]string, 0, len(base)+len(overrides))
354		for _, kv := range base {
355			eq := strings.IndexByte(kv, '=')
356			if eq < 0 {
357				env = append(env, kv)
358				continue
359			}
360			if skip[kv[:eq]] {
361				continue
362			}
363			env = append(env, kv)
364		}
365		for _, key := range keys {
366			env = append(env, key+"="+overrides[key])
367		}
368		return env
369	}
