	var body map[string]any
	require.NoError(t, json.Unmarshal([]byte(events[0].Body), &body))
	assert.Equal(t, "orphaned_harness_child", body["reason"])
	assert.Equal(t, orphanBeadID, body["bead_id"])
	assert.Equal(t, float64(7777), body["process_pid"])
	assert.Equal(t, float64(1), body["process_parent_pid"])
	assert.Contains(t, body, "claim_owner_pid", "claim owner PID should be in diagnosis")
	assert.Contains(t, body, "diagnosis", "diagnosis should be recorded")

	emittedAttention := emitted["loop.operator_attention"]
	require.Len(t, emittedAttention, 1, "operator attention should be emitted")
	assert.Equal(t, "orphaned_harness_child", emittedAttention[0]["reason"])
	assert.Equal(t, orphanBeadID, emittedAttention[0]["bead_id"])
	assert.Equal(t, float64(7777), emittedAttention[0]["process_pid"])
}

