1	// Package workerstatus reports on live "ddx work" / "ddx try" processes,
2	// scoped to a specific project root by default.
3	//
4	// Operators and agents asking "is the worker still working beads?" must be
5	// able to answer the question for one project at a time. A global process
6	// scan ("ps aux | grep ddx work") returns workers from every checkout on the
7	// machine and produces a misleading "yes, working" signal when the worker
8	// belongs to a different repository. This package filters live workers by
9	// the resolved project root so the answer always matches the question.
10	package workerstatus
11	
12	import (
13		"context"
14		"path/filepath"
15		"regexp"
16		"strings"
17		"time"
18	)
19	
20	// LiveWorker describes one running ddx worker process.
21	type LiveWorker struct {
22		PID               int       `json:"pid"`
23		Command           string    `json:"command"`
24		StartedAt         time.Time `json:"started_at"`
25		AgeSeconds        float64   `json:"age_seconds"`
26		Age               string    `json:"age"`
27		ProjectRoot       string    `json:"project_root"`
28		BeadID            string    `json:"bead_id,omitempty"`
29		AttemptID         string    `json:"attempt_id,omitempty"`
30		Phase             string    `json:"phase,omitempty"`
31		ChildPID          int       `json:"child_pid,omitempty"`
32		LastActivityAt    time.Time `json:"last_activity_at,omitempty"`
33		ExecutionWorktree string    `json:"execution_worktree,omitempty"`
34		Cwd               string    `json:"cwd,omitempty"`
35	}
36	
37	// Scanner discovers live ddx worker processes on the host.
38	type Scanner interface {
39		Scan(ctx context.Context) ([]LiveWorker, error)
40	}
41	
42	// New returns the platform-appropriate Scanner. On Linux this reads /proc.
43	// On other platforms it returns an empty list; the caller's tests and the
44	// --all-projects escape hatch remain meaningful regardless.
45	func New() Scanner {
46		return newSystemScanner()
47	}
48	
49	// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
50	// total) embedded in argv strings or worktree paths.
51	var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)
52	
53	// executionWorktreePattern matches the conventional execute-bead worktree
54	// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
55	// in a path. The directory name is enough to identify the worktree even when
56	// the surrounding path is unconventional.
57	var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)
58	
59	// InferBead extracts a bead ID and execution worktree path from the worker's
60	// command line and current working directory. It returns the longest worktree
61	// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
62	// the inline worker has chdir'd into the isolated worktree), and the first
63	// bead ID matched in either the command line or the worktree path.
64	//
65	// Either return value may be empty when no signal is present, which is the
66	// expected case for a long-running `ddx work` drain that has not yet started
67	// a specific bead.
68	func InferBead(cmdline, cwd string) (beadID, worktree string) {
69		worktree = extractWorktreePath(cwd)
70		if worktree == "" {
71			worktree = extractWorktreePath(cmdline)
72		}
73	
74		if m := beadIDPattern.FindString(worktree); m != "" {
75			beadID = m
76		}
77		if beadID == "" {
78			if m := beadIDPattern.FindString(cmdline); m != "" {
79				beadID = m
80			}
81		}
82		if beadID == "" {
83			if m := beadIDPattern.FindString(cwd); m != "" {
84				beadID = m
85			}
86		}
87		return beadID, worktree
88	}
89	
90	func extractWorktreePath(s string) string {
91		if s == "" {
92			return ""
93		}
94		if !strings.Contains(s, ".execute-bead-wt-") {
95			return ""
96		}
97		matches := executionWorktreePattern.FindStringIndex(s)
98		if matches == nil {
99			return ""
100		}
101		start := matches[0]
102		end := matches[1]
103		for start > 0 {
104			r := s[start-1]
105			if r == ' ' || r == '\x00' || r == '\t' {
106				break
107			}
108			start--
109		}
110		for end < len(s) {
111			r := s[end]
112			if r == ' ' || r == '\x00' || r == '\t' {
113				break
114			}
115			end++
116		}
117		return s[start:end]
118	}
119	
120	// FilterByProject returns workers whose ProjectRoot resolves to the same path
121	// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
122	// filepath.EvalSymlinks so a symlinked checkout matches its real path.
123	func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
124		target := canonicalPath(projectRoot)
125		out := make([]LiveWorker, 0, len(workers))
126		for _, w := range workers {
127			if SamePath(w.ProjectRoot, target) {
128				out = append(out, w)
129			}
130		}
131		return out
132	}
133	
134	// SamePath reports whether a and b refer to the same on-disk location after
135	// canonicalisation. It tolerates empty inputs (returning false) so callers
136	// can safely compare optional fields without prefiltering.
137	func SamePath(a, b string) bool {
138		ca := canonicalPath(a)
139		cb := canonicalPath(b)
140		if ca == "" || cb == "" {
141			return false
142		}
143		return ca == cb
144	}
145	
146	func canonicalPath(p string) string {
147		if strings.TrimSpace(p) == "" {
148			return ""
149		}
150		abs, err := filepath.Abs(p)
151		if err != nil {
152			abs = filepath.Clean(p)
153		}
154		if resolved, err := filepath.EvalSymlinks(abs); err == nil {
155			return resolved
156		}
157		return abs
158	}
159	
160	// FormatAge renders a duration as a short human-readable string mirroring
161	// the conventions used by the server-backed worker list (`5s`, `12m`,
162	// `1h30m`). It is intended for terminal output; JSON output uses
163	// AgeSeconds as the numeric source of truth.
164	func FormatAge(d time.Duration) string {
165		if d < time.Minute {
166			if d < 0 {
167				d = 0
168			}
169			return roundedSeconds(d)
170		}
171		if d < time.Hour {
172			return roundedMinutes(d)
173		}
174		hours := int(d.Hours())
175		mins := int(d.Minutes()) % 60
176		if mins == 0 {
177			return durationHours(hours)
178		}
179		return durationHoursMinutes(hours, mins)
180	}
181	
182	func roundedSeconds(d time.Duration) string {
183		secs := int(d.Seconds())
184		return durationSeconds(secs)
185	}
186	
187	func roundedMinutes(d time.Duration) string {
188		mins := int(d.Minutes())
189		return durationMinutes(mins)
190	}
191	
192	func durationSeconds(n int) string { return formatUnit(n, "s") }
193	func durationMinutes(n int) string { return formatUnit(n, "m") }
194	func durationHours(n int) string   { return formatUnit(n, "h") }
195	func durationHoursMinutes(h, m int) string {
196		return formatUnit(h, "h") + formatUnit(m, "m")
197	}
198	
199	func formatUnit(n int, unit string) string {
200		if n < 0 {
201			n = 0
202		}
203		return itoa(n) + unit
204	}
205	
206	func itoa(n int) string {
207		if n == 0 {
208			return "0"
209		}
210		neg := n < 0
211		if neg {
212			n = -n
213		}
214		var digits [20]byte
215		i := len(digits)
216		for n > 0 {
217			i--
218			digits[i] = byte('0' + n%10)
219			n /= 10
220		}
221		out := string(digits[i:])
222		if neg {
223			return "-" + out
224		}
225		return out
226	}
